// sos dp
int dp[N];
void solve(int CASE)
{
	int n, m; cin >> n >> m;
	fa(i, 0, (1ll << m) - 1)dp[i] = INF;

	var a = vector<int>(n + 1);
	fa(i, 1, n) {
		string s; cin >> s;
		int now = 0;
		fa(j, 0, m - 1)if (s[j] == '1')now += (1 << j);
		a[i] = now;
	}

	int k; cin >> k;
	var b = vector<int>(k + 1);
	fa(i, 1, k) {
		string s; cin >> s;
		int now = 0;
		fa(j, 0, m - 1)if (s[j] == '1')now += (1 << j);
		b[i] = now;
	}

	// 枚举所有药物组合 O(2 ^ k)
	dp[0] = 0;
	fa(mask, 1, (1 << k) - 1) {
		int now = 0, cnt = 0;
		fa(i, 0, k - 1)if (mask & (1 << i)) {
			now |= b[i + 1];
			cnt++;
		}
		dp[now] = min(dp[now], cnt);
	}

	// sos dp 超集 -> 子集 O(m * 2 ^ m)
	fa(i, 0, m - 1)
		fa(mask, 0, (1 << m) - 1)
		if (!(mask & (1 << i)))
			dp[mask] = min(dp[mask], dp[mask ^ (1 << i)]);

	fa(i, 1, n) {
		if (dp[a[i]] == INF)cout << -1 << endl;
		else cout << dp[a[i]] << endl;
	}
	return;
}
